SELECT COUNT(*) as total_count, SUM(CASE WHEN audit_decision = 'APPROVED' THEN 1 ELSE 0 END) as approved_count, SUM(CASE WHEN audit_decision = 'REJECTED' THEN 1 ELSE 0 END) as rejected_count, SUM(CASE WHEN audit_decision = 'MANUAL' THEN 1 ELSE 0 END) as manual_count, AVG(audit_duration) as avg_duration, SUM(CASE WHEN status = 1 THEN 1 ELSE 0 END) as success_count, SUM(CASE WHEN status = 0 THEN 1 ELSE 0 END) as failed_count FROM ai_audit_records WHERE audit_type = #{auditType}
